// DO NOT EDIT imports — all available components are pre-imported.
import React, { useState, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';


// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>; // Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate
  columns: Array<{ id?: string; name?: string }>; // Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}]
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when a task is moved, edited, or created. Payload: { action, taskId, data } */
type ActionTaskUpdatePayload = { action: string; taskId: string; data: { column: string } };

// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: A task was moved, edited, or created by another user — update it in the board */
type StreamTaskChanged = { action?: 'create' | 'move' | 'edit' | 'delete'; task?: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string } };

function useComponent(props: Props) {
  // Actions — fire-and-forget to agent
  const fireTaskUpdate = (payload: ActionTaskUpdatePayload) => {
    window.dispatchEvent(new CustomEvent('ggui:action', { detail: { action: 'taskUpdate', payload } }));
  };

  // Streams — real-time from agent via window events
  const [taskChangedLatest, setTaskChangedLatest] = React.useState<StreamTaskChanged | null>(null);

  // State
  const [tasks, setTasks] = useState(props.tasks || []);
  const [editingTaskId, setEditingTaskId] = useState<string | null>(null);
  const [editingTitle, setEditingTitle] = useState('');
  const [addingToColumn, setAddingToColumn] = useState<string | null>(null);
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');

  // Sync with incoming stream events
  // Listen for incoming stream events from agent
  React.useEffect(() => {
    const handleAgentData = (event: Event) => {
      const customEvent = event as CustomEvent<StreamTaskChanged>;
      const data = customEvent.detail;
      setTaskChangedLatest(data);
      // Process the event
      if (data.action === 'create' && data.task) {
        setTasks(prev => [...prev, data.task!]);
      } else if (data.action === 'move' && data.task) {
        setTasks(prev => prev.map(t => t.id === data.task!.id ? data.task! : t));
      } else if (data.action === 'edit' && data.task) {
        setTasks(prev => prev.map(t => t.id === data.task!.id ? data.task! : t));
      } else if (data.action === 'delete' && data.task) {
        setTasks(prev => prev.filter(t => t.id !== data.task!.id));
      }
    };
    window.addEventListener('ggui:agent-data', handleAgentData);
    return () => window.removeEventListener('ggui:agent-data', handleAgentData);
  }, []);

  // Update tasks from props if they change
  React.useEffect(() => {
    if (props.tasks) {
      setTasks(props.tasks);
    }
  }, [props.tasks]);

  // Computed values
  const groupedTasks = React.useMemo(() => {
    const grouped: Record<string, typeof tasks> = {};
    props.columns?.forEach(col => {
      grouped[col.id || ''] = [];
    });
    tasks.forEach(task => {
      const colId = task.column || 'todo';
      if (!grouped[colId]) grouped[colId] = [];
      grouped[colId].push(task);
    });
    return grouped;
  }, [tasks, props.columns]);

  const totalTasks = tasks.length;
  const completedTasks = tasks.filter(t => t.column === 'done').length;

  // Handlers
  const handleMoveTask = useCallback((taskId: string, fromColumn: string, toColumn: string) => {
    setTasks(prev => prev.map(t => t.id === taskId ? { ...t, column: toColumn } : t));
    fireTaskUpdate({ action: 'move', taskId, data: { column: toColumn } });
  }, [fireTaskUpdate]);

  const handleStartEdit = useCallback((taskId: string, currentTitle: string) => {
    setEditingTaskId(taskId);
    setEditingTitle(currentTitle);
  }, []);

  const handleSaveEdit = useCallback((taskId: string) => {
    if (editingTitle.trim()) {
      setTasks(prev => prev.map(t => t.id === taskId ? { ...t, title: editingTitle } : t));
      fireTaskUpdate({ action: 'edit', taskId, data: { column: tasks.find(t => t.id === taskId)?.column || 'todo' } });
    }
    setEditingTaskId(null);
    setEditingTitle('');
  }, [editingTitle, tasks, fireTaskUpdate]);

  const handleCancelEdit = useCallback(() => {
    setEditingTaskId(null);
    setEditingTitle('');
  }, []);

  const handleAddTask = useCallback((columnId: string) => {
    if (newTaskTitle.trim()) {
      const newTaskId = `task-${Date.now()}`;
      const newTask = {
        id: newTaskId,
        title: newTaskTitle,
        priority: newTaskPriority,
        column: columnId,
        assignee: '',
        dueDate: ''
      };
      setTasks(prev => [...prev, newTask]);
      fireTaskUpdate({ action: 'create', taskId: newTaskId, data: { column: columnId } });
      setNewTaskTitle('');
      setNewTaskPriority('medium');
      setAddingToColumn(null);
    }
  }, [newTaskTitle, newTaskPriority, fireTaskUpdate]);

  const priorityColor = (priority?: string) => {
    switch (priority) {
      case 'high':
        return 'error';
      case 'medium':
        return 'warning';
      case 'low':
      default:
        return 'success';
    }
  };

  return { fireTaskUpdate, taskChangedLatest, tasks, editingTaskId, editingTitle, setEditingTitle, addingToColumn, setAddingToColumn, newTaskTitle, setNewTaskTitle, newTaskPriority, setNewTaskPriority, groupedTasks, totalTasks, completedTasks, handleMoveTask, handleStartEdit, handleSaveEdit, handleCancelEdit, handleAddTask, priorityColor };
}

export default function Component(props: Props) {
  const state = useComponent(props);

  return (
    <Container maxWidth="3xl" padding={24}>
      <Stack gap={24}>
        {/* Summary Bar */}
        <Box background="var(--ggui-color-primary-50, #f0f9ff)" borderRadius="var(--ggui-shape-radius-lg, 12px)" paddingX={24} paddingY={16}>
          <Row align="center" justify="between">
            <Stack direction="horizontal" gap={8} align="center">
              <Heading level={3} color="var(--ggui-color-primary-900, #0c4a6e)">Kanban Board</Heading>
              <Divider orientation="vertical" margin={8} color="var(--ggui-color-primary-200, #bae6fd)" />
              <Text variant="label" color="var(--ggui-color-primary-700, #0369a1)">
                {state.completedTasks} of {state.totalTasks} tasks completed
              </Text>
            </Stack>
            <Progress value={(state.completedTasks / Math.max(state.totalTasks, 1)) * 100} variant="success" size="sm" />
          </Row>
        </Box>

        {/* Kanban Columns */}
        <Row gap={24} wrap>
          {props.columns?.map(column => {
            const columnId = column.id || '';
            const columnTasks = state.groupedTasks[columnId] || [];

            return (
              <Box key={columnId} style={{ flex: '1 1 300px', minWidth: '300px' }}>
                <Stack gap={16}>
                  {/* Column Header */}
                  <Box>
                    <Row align="center" justify="between" gap={8}>
                      <Stack direction="horizontal" gap={8} align="center">
                        <Heading level={4} color="var(--ggui-color-onSurface, #18181b)">{column.name}</Heading>
                        <Badge variant="secondary" size="sm">{columnTasks.length}</Badge>
                      </Stack>
                    </Row>
                  </Box>

                  {/* Task Cards */}
                  <Stack gap={12}>
                    {columnTasks.map(task => (
                      <Card key={task.id} padding={16} shadow="sm" border radius="md">
                        <Stack gap={12}>
                          {/* Task Title */}
                          {state.editingTaskId === task.id ? (
                            <Stack gap={8}>
                              <Input
                                label="Task title"
                                value={state.editingTitle}
                                onChange={state.setEditingTitle}
                                size="sm"
                              />
                              <Row gap={8} justify="end">
                                <Button variant="ghost" size="xs" onClick={state.handleCancelEdit}>Cancel</Button>
                                <Button variant="primary" size="xs" onClick={() => state.handleSaveEdit(task.id || '')}>Save</Button>
                              </Row>
                            </Stack>
                          ) : (
                            <Row align="center" justify="between" gap={8}>
                              <Text variant="body" color="var(--ggui-color-onSurface, #18181b)">{task.title || 'Untitled'}</Text>
                              <Button as={Clickable} variant="ghost" size="xs" onClick={() => state.handleStartEdit(task.id || '', task.title || '')}>
                                <Icon name="edit" size={14} />
                              </Button>
                            </Row>
                          )}

                          {/* Priority Badge */}
                          {task.priority && (
                            <Badge variant={state.priorityColor(task.priority) as any} size="sm" pill>
                              {task.priority.charAt(0).toUpperCase() + task.priority.slice(1)}
                            </Badge>
                          )}

                          {/* Assignee + Due Date */}
                          <Row align="center" justify="between" gap={8}>
                            {task.assignee ? (
                              <Avatar name={task.assignee} size="sm" shape="circle" />
                            ) : (
                              <Box style={{ width: '32px', height: '32px' }} />
                            )}
                            {task.dueDate && (
                              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">{task.dueDate}</Text>
                            )}
                          </Row>

                          {/* Move Button */}
                          <Dropdown
                            trigger={<Button variant="outline" size="xs" fullWidth>Move</Button>}
                            options={props.columns?.filter(c => c.id !== columnId).map(c => ({
                              value: c.id || '',
                              label: c.name || ''
                            })) || []}
                            value=""
                            onChange={(toColumn) => state.handleMoveTask(task.id || '', columnId, toColumn)}
                            placement="bottom-start"
                          />
                        </Stack>
                      </Card>
                    ))}
                  </Stack>

                  {/* Add Task Section */}
                  {state.addingToColumn === columnId ? (
                    <Card padding={16} shadow="sm" border radius="md" background="var(--ggui-color-surfaceVariant, #f4f4f5)">
                      <Stack gap={12}>
                        <Input
                          label="Task title"
                          placeholder="Enter task title"
                          value={state.newTaskTitle}
                          onChange={state.setNewTaskTitle}
                          size="sm"
                        />
                        <Select
                          label="Priority"
                          value={state.newTaskPriority}
                          onChange={(v) => state.setNewTaskPriority(v as any)}
                          options={[
                            { value: 'low', label: 'Low' },
                            { value: 'medium', label: 'Medium' },
                            { value: 'high', label: 'High' }
                          ]}
                          size="sm"
                        />
                        <Row gap={8} justify="end">
                          <Button variant="ghost" size="xs" onClick={() => { state.setAddingToColumn(null); state.setNewTaskTitle(''); state.setNewTaskPriority('medium'); }}>Cancel</Button>
                          <Button variant="primary" size="xs" onClick={() => state.handleAddTask(columnId)}>Add</Button>
                        </Row>
                      </Stack>
                    </Card>
                  ) : (
                    <Button variant="ghost" size="sm" fullWidth onClick={() => state.setAddingToColumn(columnId)}>+ Add Task</Button>
                  )}
                </Stack>
              </Box>
            );
          })}
        </Row>
      </Stack>
    </Container>
  );
}
